import (
	"html/template"
	"net/http"
)

type comment struct {
	Author string
	Text   string
}

var comments []comment

func commentHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.ParseFiles("templates/comments.html"))
	tmpl.Execute(w, comments)
}

func main() {
	// Initialize comments slice
	comments = []comment{
		{"John Doe", "This is the first comment."},
		{"Jane Smith", "This is the second comment. It includes formatting: <b>bold</b>."},
	}

	http.HandleFunc("/comments", commentHandler)
	http.ListenAndServe(":8080", nil)
}